import React, { useEffect, useState, useCallback, useRef } from 'react';
import { useSelector, useDispatch } from 'react-redux';
import { useSearchParams } from 'react-router-dom';
import { setJobs, appendJobs, setLoading, setFilters, updateJobInList } from '../store/jobsSlice';
import { jobsAPI } from '../services/api';
import JobCard from '../components/JobCard';
import FilterPanel from '../components/FilterPanel';

function SkeletonCard() {
  return (
    <div className="glass-card p-5 space-y-3">
      <div className="flex gap-3">
        <div className="skeleton w-10 h-10 rounded-lg" />
        <div className="flex-1 space-y-2">
          <div className="skeleton h-4 w-3/4 rounded" />
          <div className="skeleton h-3 w-1/2 rounded" />
        </div>
      </div>
      <div className="flex gap-2">
        <div className="skeleton h-5 w-16 rounded-full" />
        <div className="skeleton h-5 w-20 rounded-full" />
      </div>
      <div className="skeleton h-8 w-full rounded-lg" />
    </div>
  );
}

const LIMIT = 20;

export default function JobBoard() {
  const dispatch = useDispatch();
  const { jobs, total, pages, page, loading, filters } = useSelector((state) => state.jobs);
  const { isAuthenticated } = useSelector((state) => state.auth);
  const [searchParams] = useSearchParams();
  const [localFilters, setLocalFilters] = useState({
    type: searchParams.get('type') || filters.type || '',
    search: filters.search || '',
    remote: filters.remote || false,
    source: filters.source || '',
  });
  const debounceRef = useRef(null);

  const fetchJobs = useCallback(async (pageNum = 1, append = false, currentFilters = localFilters) => {
    dispatch(setLoading(true));
    try {
      const params = { page: pageNum, limit: LIMIT };
      if (currentFilters.type) params.type = currentFilters.type;
      if (currentFilters.search) params.search = currentFilters.search;
      if (currentFilters.remote) params.remote = 'true';
      if (currentFilters.source) params.source = currentFilters.source;

      const res = await jobsAPI.getJobs(params);
      if (append) {
        dispatch(appendJobs(res.data));
      } else {
        dispatch(setJobs(res.data));
      }
    } catch (err) {
      console.error('Failed to fetch jobs:', err.message);
    } finally {
      dispatch(setLoading(false));
    }
  }, [dispatch, localFilters]);

  useEffect(() => {
    fetchJobs(1, false, localFilters);
  }, []); // initial load

  const handleFilterChange = (newFilters) => {
    setLocalFilters(newFilters);
    dispatch(setFilters(newFilters));
    if (debounceRef.current) clearTimeout(debounceRef.current);
    debounceRef.current = setTimeout(() => {
      fetchJobs(1, false, newFilters);
    }, 400);
  };

  const handleLoadMore = () => {
    if (page < pages) fetchJobs(page + 1, true);
  };

  const handleSave = async (job) => {
    if (!isAuthenticated) return;
    try {
      const res = await jobsAPI.saveJob(job._id);
      dispatch(updateJobInList({ _id: job._id, isSaved: res.data.saved }));
    } catch (_) {}
  };

  const handleApply = async (job) => {
    if (!isAuthenticated) return;
    try {
      await jobsAPI.applyJob(job._id);
      dispatch(updateJobInList({ _id: job._id, isApplied: true }));
    } catch (_) {}
  };

  const hasMore = page < pages;

  return (
    <div className="page-bg pt-20 pb-10 px-4 min-h-screen">
      <div className="max-w-7xl mx-auto">
        {/* Header */}
        <div className="mb-6 animate-fade-in">
          <h1 className="text-2xl font-bold text-white">
            🌐 Live Opportunities
          </h1>
          <p className="text-gray-400 text-sm mt-1">
            Real-time jobs from Remotive, Arbeitnow, scholarships, and your CSV uploads
          </p>
        </div>

        <div className="flex flex-col lg:flex-row gap-6">
          {/* Filter sidebar */}
          <div className="lg:w-64 flex-shrink-0">
            <div className="sticky top-20">
              <FilterPanel filters={localFilters} onChange={handleFilterChange} total={total} />
            </div>
          </div>

          {/* Job grid */}
          <div className="flex-1">
            {/* Sources banner */}
            <div className="flex flex-wrap gap-2 mb-4">
              {[
                { label: '📡 Remotive', color: 'text-blue-400 bg-blue-500/10 border-blue-500/20' },
                { label: '🇩🇪 Arbeitnow', color: 'text-green-400 bg-green-500/10 border-green-500/20' },
                { label: '🏅 Scholarships', color: 'text-yellow-400 bg-yellow-500/10 border-yellow-500/20' },
                { label: '📄 CSV Upload', color: 'text-purple-400 bg-purple-500/10 border-purple-500/20' },
              ].map(s => (
                <span key={s.label} className={`text-xs px-3 py-1 rounded-full border font-medium ${s.color}`}>
                  {s.label}
                </span>
              ))}
            </div>

            {loading && jobs.length === 0 ? (
              <div className="grid sm:grid-cols-2 xl:grid-cols-3 gap-4">
                {Array.from({ length: 6 }).map((_, i) => <SkeletonCard key={i} />)}
              </div>
            ) : jobs.length === 0 ? (
              <div className="glass-card p-12 text-center">
                <div className="text-5xl mb-4">🔍</div>
                <p className="text-white font-semibold mb-2">No results found</p>
                <p className="text-gray-400 text-sm">Try adjusting your filters or search terms</p>
              </div>
            ) : (
              <>
                <div className="grid sm:grid-cols-2 xl:grid-cols-3 gap-4">
                  {jobs.map((job) => (
                    <JobCard
                      key={job._id}
                      job={job}
                      onSave={handleSave}
                      onApply={handleApply}
                    />
                  ))}
                  {loading && Array.from({ length: 3 }).map((_, i) => <SkeletonCard key={`sk${i}`} />)}
                </div>

                {hasMore && (
                  <div className="text-center mt-8">
                    <button
                      onClick={handleLoadMore}
                      disabled={loading}
                      className="btn-secondary disabled:opacity-50"
                    >
                      {loading ? 'Loading...' : `Load More (${total - jobs.length} remaining)`}
                    </button>
                  </div>
                )}

                <p className="text-center text-gray-600 text-xs mt-6">
                  Showing {jobs.length} of {total} opportunities
                </p>
              </>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
